import axios from 'axios';

const apiClient = axios.create({
  baseURL: process.env.NEXT_PUBLIC_API_URL,
  withCredentials: true,
});

export default apiClient;


import apiClient from '@/lib/api';
import type { ApiResponse } from '@/types/api';
import type { User } from '@/domains/auth/models/auth';
import type { UserDto } from '@/domains/auth/api/auth.dto';
import { toUserModel } from '@/domains/auth/api/auth.mapper';

export const getMe = async (accessToken?: string | null): Promise<User | null> => {
  if (!accessToken) return null;

  const response = await apiClient.get<ApiResponse<UserDto | null>>('/api/v1/users/me', {
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
  });
  return response.data.data ? toUserModel(response.data.data) : null;
};


export { RequireAuth } from './components/require-auth';
export { useAuth, useInitialAuth } from './hooks/use-auth';
export { useUserQuery, useLogoutMutation, authKeys } from './hooks/use-auth-query';
